   FICCC Design Tokens & Global Styles
   Palette: "Gathered Warmth" (D007)
   ========================================================================== */

/* --- Font imports (self-hosted via fontsource) --- */
@import '@fontsource-variable/lora';
@import '@fontsource-variable/inter';

/* ==========================================================================
   CSS Custom Properties
   ========================================================================== */

:root {
  /* --- Colors: Gathered Warmth palette --- */
  --color-bg:          #FAF8F5;  /* off-white background       */
  --color-stone:       #E8E0D8;  /* warm stone / borders        */
  --color-terracotta:  #C4745A;  /* muted terracotta / accent   */
  --color-ink:         #1A1A2E;  /* deep ink / headings         */
