---
interface Props {
  times: { label: string; time: string }[];
}

const { times } = Astro.props;
---

<section class="service-times" aria-label="Service Times">
  <div class="service-times__inner">
    {times.map((entry) => (
      <div class="service-times__entry">
        <span class="service-times__label">{entry.label}</span>
        <span class="service-times__time">{entry.time}</span>
      </div>
    ))}
  </div>
</section>

<style>
  .service-times {
    background-color: var(--color-stone);
    padding: var(--space-8) var(--space-6);
  }

  .service-times__inner {
    max-width: var(--max-width);
    margin-inline: auto;
    display: flex;
    justify-content: center;
    gap: var(--space-12);
    flex-wrap: wrap;
  }

  .service-times__entry {
    display: flex;
    flex-direction: column;
    align-items: center;
    gap: var(--space-1);
    text-align: center;
  }

  .service-times__label {
    font-family: var(--font-body);
    font-size: var(--text-sm);
    color: var(--color-body);
    text-transform: uppercase;
    letter-spacing: 0.05em;
  }

  .service-times__time {
    font-family: var(--font-heading);
    font-size: var(--text-xl);
    color: var(--color-ink);
    line-height: var(--leading-tight);
  }

  @media (max-width: 640px) {
    .service-times__inner {
      flex-direction: column;
      align-items: center;
      gap: var(--space-6);
    }
  }
</style>

---
interface Props {
  pillars: { title: string; description: string }[];
}

const { pillars } = Astro.props;
---

<section class="pillars" aria-label="Who We Are">
  <div class="pillars__inner">
    <h2 class="pillars__heading">Who We Are</h2>
    <div class="pillars__grid">
      {pillars.map((pillar) => (
        <div class="pillars__card">
          <h3 class="pillars__title">{pillar.title}</h3>
          <p class="pillars__desc">{pillar.description}</p>
        </div>
      ))}
    </div>
  </div>
</section>

<style>
  .pillars {
    padding: var(--space-16) var(--space-6);
    background-color: var(--color-bg);
  }

  .pillars__inner {
    max-width: var(--max-width);
    margin-inline: auto;
  }

  .pillars__heading {
    font-family: var(--font-heading);
    font-size: var(--text-3xl);
    color: var(--color-ink);
    text-align: center;
    margin-block-end: var(--space-12);
  }

  .pillars__grid {
    display: grid;
    grid-template-columns: repeat(3, 1fr);
    gap: var(--space-8);
  }

  .pillars__card {
    background-color: var(--color-bg);
    border: 1px solid var(--color-stone);
